package Entites;import java.time.LocalDate;public class MedicalRecords {    private String recordId;    private String patientId;    private String doctorId;    private LocalDate visitDate;    private String diagnosis;    private String prescription;    private String testResults;    private String notes;    public MedicalRecords(String recordId, String patientId,                          LocalDate visitDate, String doctorId,                          String diagnosis, String prescription,                          String testResults, String notes) {        this.recordId = recordId;        this.patientId = patientId;        this.visitDate = visitDate;        this.doctorId = doctorId;        this.diagnosis = diagnosis;        this.prescription = prescription;        this.testResults = testResults;        this.notes = notes;    }}